SELECT TOP 1 SUM(WH.[TEMPERATURE]) AS TOTAL_TEMP,
	COUNT(*) AS DAYS,
	AVG(WH.[TEMPERATURE]) AS AVG_TEMP 
FROM [WEATHER_HISTORIES] WH 
WHERE WH.[IsDeleted] = 0 
	AND WH.[CITY_ID] = @PRM_WEATHER_HISTORY_CITY_ID 
	AND WH.[RECORDED_DATE] > DATEADD(DAY, -30,
	GETDATE()) 